-- Parte 2: Limpiar más tablas referenciadas

-- Definir los IDs en una CTE para reutilizar
WITH demo_ids AS (
  SELECT unnest(ARRAY[
    'a1000000-0000-0000-0000-000000000001'::uuid, 'a2000000-0000-0000-0000-000000000002'::uuid,
    'a3000000-0000-0000-0000-000000000003'::uuid, 'a4000000-0000-0000-0000-000000000004'::uuid,
    'a5000000-0000-0000-0000-000000000005'::uuid, 'a6000000-0000-0000-0000-000000000006'::uuid,
    'a7000000-0000-0000-0000-000000000007'::uuid, 'a8000000-0000-0000-0000-000000000008'::uuid,
    'a9000000-0000-0000-0000-000000000009'::uuid, 'aa000000-0000-0000-0000-000000000010'::uuid,
    '4289b42c-baba-4a4e-ad09-f806788f86ca'::uuid, '1c1e8fd3-5a03-4303-afef-73291c32f644'::uuid,
    'd549977a-7582-4f22-8e18-459b793a14e0'::uuid, '00000000-0000-0000-0000-00000000de00'::uuid,
    '026b4a6a-ea0e-4d93-8abb-93b15cc075c2'::uuid, '7e9f2f2e-ce8d-4c83-84da-b2b46370ed52'::uuid
  ]) AS id
)
DELETE FROM audit_logs WHERE organization_id IN (SELECT id FROM demo_ids);

